using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default (reflection-based) resolver — resolves any type.
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// ─── 1. Strongly-typed metadata: GetTypeInfo<T>() ───────────────────────────
// Returns JsonTypeInfo<T> directly — no casting from the non-generic base.
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"[typed]   Got JsonTypeInfo<{personInfo.Type.Name}>, kind = {personInfo.Kind}");

// ─── 2. Probe without throwing: TryGetTypeInfo ──────────────────────────────
// An empty resolver chain → resolves nothing.
var restricted = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine()   // no resolvers
};

// Probe for Person on the *restricted* options — should return false, not throw.
if (restricted.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"[probe]   Metadata found: {info!.Type.Name}");
}
else
{
    Console.WriteLine("[probe]   No metadata for Person — and no exception was thrown.");
}

// Probe on the *full* options — should succeed.
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info2))
{
    Console.WriteLine($"[probe]   Metadata found for {info2!.Type.Name} on full options.");
}

record Person(string Name, int Age);

